#include<bits/stdc++.h>
#define rep(a,b,c) for(short c=(a);c<=(b);++c)
using namespace std;
inline short read()
{
	short res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res; 
}
const short N=310;const int Mod=1e9+7;short a[N];
int dp[N][N][N];
struct Pair{short x,y;inline Pair(short xx=0,short yy=0){x=xx;y=yy;}};
vector<Pair> ou[N];
int main()
{
	int n=read(),Q=read();
	rep(1,Q,i){short l=read(),r=read(),x=read();ou[r].push_back(Pair(l,x));}
	dp[1][0][0]=1;
	rep(1,n,i)
	{
		for(Pair v: ou[i])
		{
			short l=v.x,x=v.y;rep(0,i-1,k)
			{
				short lm=max(k-1,0);
				rep(0,lm,o)switch(x)
				{
					case 1: if(l<=k)dp[i][k][o]=0;break;
					case 2: if(l>k||l<=o)dp[i][k][o]=0;break;
					case 3: if(l>o)dp[i][k][o]=0;break;
				}
			}
		}
		if(i==n)break;rep(0,i-1,j)
		{
			short lm=max(0,j-1);rep(0,lm,k)
			{
				(dp[i+1][j][k]+=dp[i][j][k])%=Mod;
				(dp[i+1][i][k]+=dp[i][j][k])%=Mod;
				(dp[i+1][i][j]+=dp[i][j][k])%=Mod;
			}
		}
	}
	int ans=0;rep(0,n-1,i){short lm=max(0,i-1);rep(0,lm,j)(ans+=dp[n][i][j])%=Mod;}
	printf("%lld\n",3ll*ans%Mod);
}
